import{_ as r,k as l,g as o,e as t,o as c,c as m,f as a}from"./index-6aff7af6.js";import{P as d,a as g,b as h}from"./ProjectInfo-1b4b0650.js";import{k as u}from"./Kv-Core-2-6a594b67.js";const p="/assets/game-jam-780cf137.png",f={name:"game-jam-project",components:{ProjectHeader:d,ProjectGallery:g,ProjectInfo:h},data:()=>({singleProjectHeader:{singleProjectTitle:"Game Developer/Musician",singleProjectDate:"1994-Present",singleProjectTag:"Full Stack"},projectImages:[{id:1,title:"Project Aether",img:p},{id:2,title:"Marketplace products",img:u},{id:3,title:"KvCore login",img:l}],projectInfo:{clientHeading:"About Client",companyInfos:[{id:1,title:"Name",details:"RuneWerkz Software"},{id:2,title:"Services",details:"Full Stack Engineer"},{id:3,title:"Website",details:"N/A...yet"},{id:4,title:"Phone",details:"385-414-5721"}],objectivesHeading:"Objective",objectivesDetails:"I was invited to participate in a game jam with a group of close friends. The objective was to make a game in24 hours, and the theme was traveling.",technologies:[{title:"Tools & Technologies",techs:["Unity","C#","Ableton Pro","Adobe Audition","Yamaha PSR-SX900"]}],projectDetailsHeading:"Challenge",projectDetails:[{id:1,details:"Like most nerds, i've always dreamed of opening my own game studio. From the early days on my parents carpetplaying the Sega Genesis, I knew it was something I WANTED to do. The pragmatic part of my brain always keptme out of chasing it professionally though. The AAA industry space never really appealed to me outside of a handful of examples. (Valve? Call me.) The loss of creative control is something that always worried me."},{id:2,details:"I decided ultimately to chase programming as a profession, since it's adjacent, and in my free time I couldbegin learning the other skills I would need.  Online resources are plentiful, and the amount of courses offeredthrough sites like Udemy allowed me to get my feet wet and start working on little vertical slices of differentgame ideas I had. After a little while, I began to feel confident enough to play around with other game enginesand familiarize myself with all aspects of game creation."},{id:3,details:"The game jam was a fun way of taking it all the way to it's conclusion.  It's easy to make a bunch of demos,it's much harder to finish a game.  Engineering wise, I took a backseat and let my friend take the lead.I wanted to focus on the music.  I've played piano for most of my life, but sound design, mastering, and all the other intricacies were new to me.  Realized pretty early on I bit off a lot. But I managedto chew through it and turn out something im proud of."},{id:4,details:`The game itself, is really simple. Top down "Fish.io" type game.  Eat smaller things, get bigger, don't geteaten by something bigger. You are a black hole, consuming smaller matter, growing bigger, until allmatter is consumed and you implode into a new big bang. Birthing a new universe.  The music was meant to start eerie, and end hopeful. But that end state never made it in the 24 hours we had.  It was a great experienceand I look forward to more in the future.`}],socialSharingsHeading:"Share This",socialSharings:[{id:1,name:"Twitter",icon:"twitter",url:"https://twitter.com"},{id:2,name:"Instagram",icon:"instagram",url:"https://www.instagram.com/hession_sessions/"},{id:3,name:"Facebook",icon:"facebook",url:"https://facebook.com/"},{id:4,name:"LinkedIn",icon:"linkedin",url:"https://www.instagram.com/hession_sessions/"},{id:5,name:"Youtube",icon:"youtube",url:"https://www.youtube.com/"}]}}),mounted(){o.replace()},updated(){o.replace()}},w={class:"container mx-auto mt-10 sm:mt-20"};function y(e,j,I,b,k,P){const i=t("ProjectHeader"),n=t("ProjectGallery"),s=t("ProjectInfo");return c(),m("div",w,[a(i,{singleProjectHeader:e.singleProjectHeader},null,8,["singleProjectHeader"]),a(n,{projectImages:e.projectImages},null,8,["projectImages"]),a(s,{projectInfo:e.projectInfo},null,8,["projectInfo"])])}const A=r(f,[["render",y]]);export{A as default};
